import React, { useCallback } from "react";
import { useParams } from "react-router-dom";
import PeopleTable from "../components/PeopleTable";
import * as api from "../mock/api";

export function Managers() {
  const { eventId } = useParams();
  const list = useCallback(() => api.listManagers(eventId), [eventId]);
  const add = useCallback((uid) => api.addManager(eventId, uid), [eventId]);
  const remove = useCallback((uid) => api.removeManager(eventId, uid), [eventId]);
  const search = useCallback((q) => api.searchUsers(q), []);
  return (
    <PeopleTable
      title="Организаторы"
      breadcrumb="Редактировать мероприятие › Организаторы"
      fetchList={list}
      fetchSearch={search}
      addFn={add}
      removeFn={remove}
      testidPrefix="managers"
    />
  );
}

export function Admins() {
  const list = useCallback(() => api.listAdmins(), []);
  const add = useCallback((uid) => api.addAdmin(uid), []);
  const remove = useCallback((uid) => api.removeAdmin(uid), []);
  const search = useCallback((q) => api.searchUsers(q), []);
  return (
    <PeopleTable
      title="Администраторы"
      breadcrumb="Администрация › Администраторы"
      fetchList={list}
      fetchSearch={search}
      addFn={add}
      removeFn={remove}
      testidPrefix="admins"
    />
  );
}
